import kotlin.math.abs

fun solve(points: Array<Array<Long>>): Long {
    val n = points.size
    if (n < 4) return 0L
    var count = 0L
    val lines = mutableMapOf<String, MutableList<Pair<Int, Int>>>()

    for (i in 0 until n) {
        for (j in i + 1 until n) {
            val x1 = points[i][0]
            val y1 = points[i][1]
            val x2 = points[j][0]
            val y2 = points[j][1]
            val key = if (x1 == x2) {
                "inf_$x1"
            } else {
                val slope = (y2 - y1).toDouble() / (x2 - x1).toDouble()
                val intercept = y1.toDouble() - slope * x1.toDouble()
                // To avoid precision issues, we can use a tolerance or represent as fraction
                // Here, we just convert to string directly for simplicity
                "${slope}_$intercept"
            }
            lines.getOrPut(key) { mutableListOf() }.add(i to j)
        }
    }

    val processed = mutableSetOf<String>()
    for ((_, pairs) in lines) {
        if (pairs.size < 2) continue
        val m = pairs.size
        for (i in 0 until m) {
            for (j in i + 1 until m) {
                val (a, b) = pairs[i]
                val (c, d) = pairs[j]
                val set = setOf(a, b, c, d)
                if (set.size == 4) {
                    val sorted = set.sorted()
                    val hash = sorted.joinToString(",")
                    if (hash !in processed) {
                        processed.add(hash)
                        count++
                    }
                }
            }
        }
    }

    return count
}
